import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class SecureCodeSnippet {

    public static void main(String[] args) throws IOException {
        // Simulating user input from a web form
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Sanitize user input to prevent XSS
        String sanitizedInput = Encode.forHtml(userInput);

        // Printing sanitized user input back to the response
        try (PrintWriter out = new PrintWriter("response.html")) {
            out.println("<html>");
            out.println("<body>");
            out.println("<h1>User Input:</h1>");
            out.println(sanitizedInput);
            out.println("</body>");
            out.println("</html>");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
